const Web3 = require('web3');
// You can replace this URL with the one of your Ethereum node provider
let web3 = new Web3(new Web3.providers.HttpProvider("http://localhost:8545")); 

async function sendTransaction(to, value) {
    // Replace with your private key
    const privateKey = "0x...";  

    let transactionObject = {
        to: to,
        value: web3.utils.toWei(value.toString(), 'ether'),
        gas: 21000,
    }
    
    try{
        // Sign the transaction and send it
        const signedTx = await web3.eth.accounts.signTransaction(transactionObject, privateKey);
        const txHash = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);
        
        console.log('Transaction hash: ' + txHash);  
    } catch (error) {
        console.log("Error in sending transaction : ", error); 
    } 
}

async function callContractMethod(contractAddress, methodName, ...methodArgs) {
    try{
        // Get ABI of the smart contract 
        const contractABI = [];  
        
        let contractInstance = new web3.eth.Contract(contractABI, contractAddress);
        let result = await contractInstance.methods[methodName](...methodArgs).call();
      
        console.log('Method call result: ',result);
    } catch (error) {
        console.log("Error in calling method : ", error); 
    } 
}